namespace ChampionGameDataGenerated
{
    u32_t GetBuildHash()
    {
        return kGeneratedChampionGameDataBuildHash;
    }

    std::size_t GetChampionCount()
    {
        return sizeof(kChampionGameDataTable) / sizeof(kChampionGameDataTable[0]);
    }

    const ChampionGameData* GetChampionTable()
    {
        return kChampionGameDataTable;
    }

    const ChampionGameData* FindChampion(eChampion champion)
    {
        for (const ChampionGameData& data : kChampionGameDataTable)
        {
            if (data.champion == champion)
            {
                return &data;
            }
        }

        return nullptr;
    }
}
